mapper.select:


    and request_id = #{requestId}
    and student_user_id = #{studentUserId}
    and student_name like concat('%', #{studentName}, '%')
    and student_no like concat('%', #{studentNo}, '%')
    and business_code = #{businessCode}
    and business_name like concat('%', #{businessName}, '%')
    and after_status_code = #{afterStatusCode}

order by create_time desc, status_log_id desc
